class User(UserMixin):
    pass

@login_manager.user_loader
def load_user(user_id):
    conn = mysql.connector.connect(host='localhost', database='your_database')
    cursor = conn.cursor()
    cursor.execute("SELECT id, username FROM users WHERE id=%s", (int(user_id),))
    user = cursor.fetchone()
    if not user:
        return None
    user_obj = User()
    user_obj.id = user[0]
    user_obj.username = user[1]
    return user_obj

posts = {}

def add_post(user_id, post):
    posts[user_id] = posts.get(user_id, []) + [post]

def delete_post(user_id, post_id):
    if user_id not in posts:
        return False
    if int(post_id) not in posts[user_id]:
        return False
    del posts[user_id][int(post_id)]
    return True

@app.route('/api/delete_post', methods=['POST'])
@login_required
def delete_post_endpoint():
    post_id = request.json.get('postId')
    if not post_id or not delete_post(current_user.id, post_id):
        return jsonify({'error': 'Invalid post ID'}), 400
    return jsonify({'success': True})

